1436 template <typename LHS_t, typename RHS_t, typename Predicate,
1437           bool Commutable = false>
1438 struct BinOpPred_match : Predicate {
1439   LHS_t L;
1440   RHS_t R;
1441 
1442   BinOpPred_match(const LHS_t &LHS, const RHS_t &RHS) : L(LHS), R(RHS) {}
